"""
Lineage hash computation module.
Salt loaded from environment variable (LINEAGE_SALT) or file.
"""
import hashlib
import os

# Salt file location (fallback only)
_SALT_PATH = '/opt/lineage_salt.bin'
_cached_salt = None

def _get_salt():
    """Load salt from env var or file (cached)"""
    global _cached_salt
    if _cached_salt is not None:
        return _cached_salt
    
    # Priority 1: Environment variable (hex string)
    env_salt = os.environ.get('LINEAGE_SALT', '')
    if env_salt:
        _cached_salt = bytes.fromhex(env_salt)
        return _cached_salt
    
    # Priority 2: File (for backwards compatibility)
    if os.path.exists(_SALT_PATH):
        with open(_SALT_PATH, 'rb') as f:
            _cached_salt = f.read()
        return _cached_salt
    
    raise RuntimeError("LINEAGE_SALT env var not set and file not found at " + _SALT_PATH)

def compute_pb_hash(pb_content: bytes, chain: list) -> str:
    """
    Compute pb file hash with salt.
    
    Args:
        pb_content: Raw pb file bytes
        chain: List of previous final hashes
    
    Returns:
        16-char hex hash
    """
    h = hashlib.sha256()
    # Add previous hashes
    for c in chain:
        if isinstance(c, str):
            h.update(c.encode('utf-8'))
        else:
            h.update(str(c).encode('utf-8'))
    # Add pb content hash
    h.update(hashlib.sha256(pb_content).digest())
    # Add salt
    h.update(_get_salt())
    return h.hexdigest()[:16]

def compute_ckpt_hash(ckpt_content: bytes, chain: list) -> str:
    """
    Compute checkpoint file hash with salt.
    
    Args:
        ckpt_content: Raw checkpoint file bytes (concatenated)
        chain: List of previous final hashes
    
    Returns:
        16-char hex hash
    """
    h = hashlib.sha256()
    for c in chain:
        if isinstance(c, str):
            h.update(c.encode('utf-8'))
        else:
            h.update(str(c).encode('utf-8'))
    h.update(hashlib.sha256(ckpt_content).digest())
    h.update(_get_salt())
    return h.hexdigest()[:16]

def compute_final_hash(pb_hash: str, ckpt_hash: str) -> str:
    """
    Compute final hash from pb and checkpoint hashes.
    
    Args:
        pb_hash: 16-char pb hash
        ckpt_hash: 16-char checkpoint hash
    
    Returns:
        16-char hex final hash
    """
    h = hashlib.sha256()
    h.update(pb_hash.encode('utf-8'))
    h.update(ckpt_hash.encode('utf-8'))
    h.update(_get_salt())
    return h.hexdigest()[:16]

def verify_chain(lineage: list, pb_content: bytes, ckpt_content: bytes, iteration: int) -> bool:
    """
    Verify the lineage chain for a specific iteration.
    
    Args:
        lineage: Full lineage list [{i, pb, ckpt, final}, ...]
        pb_content: Current pb file bytes
        ckpt_content: Current checkpoint file bytes  
        iteration: Iteration number to verify
    
    Returns:
        True if valid, False if tampered
    """
    # Find entry for this iteration
    entry = None
    for item in lineage:
        if item.get('i') == iteration:
            entry = item
            break
    
    if not entry:
        return False
    
    # Get chain up to this iteration
    prev_finals = [item.get('final', '') for item in lineage if item.get('i', -1) < iteration]
    
    # Recompute hashes
    computed_pb = compute_pb_hash(pb_content, prev_finals)
    computed_ckpt = compute_ckpt_hash(ckpt_content, prev_finals)
    computed_final = compute_final_hash(computed_pb, computed_ckpt)
    
    return (entry.get('pb') == computed_pb and 
            entry.get('ckpt') == computed_ckpt and 
            entry.get('final') == computed_final)
